## 4. `/users` leaks PII with no authentication (A01: Broken Access Control, A02: Cryptographic/Sensitive Data Exposure)

The endpoint returns names and email addresses to anyone. Even with mock data, this pattern is the template for a real leak. Minimum fix — require auth and omit emails unless the caller is authorized:

```js
function requireAuth(req, res, next) {
  const token = req.get('authorization')?.replace(/^Bearer\s+/i, '');
  if (!token || !isValidToken(token)) {
    return res.status(401).json({ error: 'unauthorized' });
  }
  req.user = decodeToken(token);
  next();
}

app.get('/users', requireAuth, (req, res) => {
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob',   email: 'bob@example.com' },
  ];
  // Only return email to admins
  const safe = users.map(u =>
    req.user.role === 'admin' ? u : { id: u.id, name: u.name }
  );
  res.json(safe);
