    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]); // drop email unless caller is authorized
});

// Central error handler — never leak stack traces
app.use((err, req, res, _next) => {
  console.error(err);
  res.status(500).json({ error: 'internal_error' });
});

const server = app.listen(3000, '127.0.0.1', () => {
