const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// 1. Security headers
app.use(helmet());

// 2. Explicit JSON body limit (applied now so future routes inherit it)
app.use(express.json({ limit: '10kb' }));

// 3. Rate limit all routes
app.use(rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// 4. If /users ever returns real data, require auth + authorization
function requireAuth(req, res, next) {
  // verify JWT / session here; reject on failure
  return res.status(501).json({ error: 'auth not implemented' });
}

app.get('/users', requireAuth, (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// 5. Centralized error handler that never leaks stack traces
app.use((err, req, res, _next) => {
  console.error(err);
  res.status(500).json({ error: 'internal error' });
});

// 6. Bind to loopback unless external access is required
const HOST = process.env.HOST || '127.0.0.1';
app.listen(3000, HOST, () => {
  console.log(`Server running on ${HOST}:3000`);
});

module.exports = app;
```

