const { z } = require('zod');
const UserQuery = z.object({ limit: z.coerce.number().int().min(1).max(100).default(20) });

app.get('/users', (req, res) => {
  const parsed = UserQuery.safeParse(req.query);
  if (!parsed.success) return res.status(400).json({ error: parsed.error.flatten() });
  // ...use parsed.data.limit
});
```

### 5. No CORS Policy (OWASP A05)
**Severity:** Low/Medium depending on deployment

Without explicit CORS config, the default (no `Access-Control-Allow-Origin`) may be fine for server-to-server, but if a browser client is ever added you'll either get blocked or be tempted to enable `*` — which is dangerous for authenticated endpoints.

**Recommendation:**
