    const token = req.headers.authorization?.replace(/^Bearer\s+/i, '');
    if (!token) return res.status(401).json({ error: 'unauthorized' });
    try {
      req.user = jwt.verify(token, process.env.JWT_SECRET, { algorithms: ['HS256'] });
      next();
    } catch { return res.status(401).json({ error: 'unauthorized' }); }
  }
  app.get('/users', requireAuth, (req, res) => { /* ... */ });
  ```
- Return the minimum fields necessary; drop `email` unless the caller is authorized to see it.
- Terminate TLS at the proxy and set `app.set('trust proxy', 1)` so rate-limit/logging sees real client IPs; enforce HSTS via helmet.

