app.get('/users', (req, res) => {
  // TODO: add authn/authz before exposing PII
  res.json([/* ... */]);
});

const PORT = process.env.PORT || 3000;
const HOST = process.env.HOST || '127.0.0.1';
app.listen(PORT, HOST, () => console.log(`Server running on ${HOST}:${PORT}`));

module.exports = app;
```

