const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
app.disable('x-powered-by');
app.use(helmet());
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

// ...routes...

app.use((err, req, res, _next) => {
  console.error(err);
  res.status(500).json({ error: 'internal_error' });
});

app.listen(3000, '127.0.0.1', () => console.log('Server running'));
```

## Bottom line
No high- or medium-severity vulnerabilities in the current code — the attack surface is essentially nil because no user input is processed. All findings are defense-in-depth hardening items that become important as the app grows (especially before adding any route that accepts `req.body`/`req.query`/`req.params`).# Security Review: app.js

